MERGE INTO CONSULTAS FIN USING (SELECT '000752AnalisisCarteraCXP' INFORME ,TO_CLOB(q'[SELECT 
  DETALLE_COMPROBANTE_CNT.VALOR_CREDITO,
  DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO,
  DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO,
  VLRAGIRAR-CASE WHEN DEBITOSAFECTADOS>0 AND DEBITOSAFECTADOS=CREDITOSAFECTADOS THEN DEBITOSAFECTADOS ELSE DEBITOSAFECTADOS-CREDITOSAFECTADOS END + ABONADO SALD,
  VLRAGIRAR-CASE WHEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO>0 AND DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO=DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO THEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO ELSE DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO-DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO END + ABONADO SALDO,
  DETALLE_COMPROBANTE_CNT.COMPANIA,
  DETALLE_COMPROBANTE_CNT.ANO,
  DETALLE_COMPROBANTE_CNT.TIPO_CPTE TIPO,
  DETALLE_COMPROBANTE_CNT.COMPROBANTE NUMERO, 
  DETALLE_COMPROBANTE_CNT.CUENTA,
  DETALLE_COMPROBANTE_CNT.FECHA,
  V_PLAN_CONTABLE.CLASECUENTA,
  TIPO_COMPROBANTE.CLASE_CONTABLE,
  DETALLE_COMPROBANTE_CNT.TERCERO, 
  TERCERO.NOMBRE NOMBRETERCERO,
  DETALLE_COMPROBANTE_CNT.VALOR_CREDITO TOTALDEUDA,
  TERCERO.SUCURSAL,
  TERCERO.DIRECCION,
  TERCERO.TELEFONOS,
  TO_DATE('s$fechaCorte$s','DD/MM/YYYY') - COMPROBANTE_CNT.s$porVencimiento$s DIFERENCIAENDIAS,
  CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY') - TRUNC(COMPROBANTE_CNT.s$porVencimiento$s) <=0 THEN VLRAGIRAR-CASE WHEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO>0 AND DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO=DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO THEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO ELSE DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO-DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO END + ABONADO ELSE 0 END POR_VENCER,
  CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY') - TRUNC(COMPROBANTE_CNT.s$porVencimiento$s) BETWEEN 1 AND 30 THEN VLRAGIRAR-CASE WHEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO>0 AND DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO=DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO THEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO ELSE DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO-DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO END + ABONADO ELSE 0 END SALDO1,
  CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY') - TRUNC(COMPROBANTE_CNT.s$porVencimiento$s) BETWEEN 31 AND 60 THEN VLRAGIRAR-CASE WHEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO>0 AND DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO=DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO THEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO ELSE DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO-DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO END + ABONADO ELSE 0 END SALDO2,
  CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY') - TRUNC(COMPROBANTE_CNT.s$porVencimiento$s) BETWEEN 61 AND 90 THEN VLRAGIRAR-CASE WHEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO>0 AND DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO=DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO THEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO ELSE DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO-DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO END + ABONADO ELSE 0 END SALDO3,
  CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY') - TRUNC(COMPROBANTE_CNT.s$porVencimiento$s) >90 THEN VLRAGIRAR-CASE WHEN DETAL]') || TO_CLOB(q'[LE_COMPROBANTE_CNT.DEBITO_AFECTADO>0 AND DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO=DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO THEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO ELSE DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO-DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO END + ABONADO ELSE 0 END SALDO4,
  DETALLE_COMPROBANTE_CNT.NRO_DOCUMENTO NODOC,
  COMPROBANTE_CNT.FECHA_VCN_DOC,
  COMPROBANTE_CNT.DESCRIPCION  
FROM DETALLE_COMPROBANTE_CNT
  INNER JOIN V_PLAN_CONTABLE
     ON DETALLE_COMPROBANTE_CNT.COMPANIA = V_PLAN_CONTABLE.COMPANIA
    AND DETALLE_COMPROBANTE_CNT.ANO      = V_PLAN_CONTABLE.ANO
    AND DETALLE_COMPROBANTE_CNT.ID       = V_PLAN_CONTABLE.ID
  INNER JOIN COMPROBANTE_CNT 
     ON DETALLE_COMPROBANTE_CNT.COMPANIA    = COMPROBANTE_CNT.COMPANIA   
    AND DETALLE_COMPROBANTE_CNT.TIPO_CPTE   = COMPROBANTE_CNT.TIPO
    AND DETALLE_COMPROBANTE_CNT.ANO         = COMPROBANTE_CNT.ANO
    AND DETALLE_COMPROBANTE_CNT.COMPROBANTE = COMPROBANTE_CNT.NUMERO
  INNER JOIN TERCERO
     ON DETALLE_COMPROBANTE_CNT.COMPANIA = TERCERO.COMPANIA 
    AND DETALLE_COMPROBANTE_CNT.TERCERO  = TERCERO.NIT 
    AND DETALLE_COMPROBANTE_CNT.SUCURSAL = TERCERO.SUCURSAL
  INNER JOIN TIPO_COMPROBANTE 
     ON DETALLE_COMPROBANTE_CNT.COMPANIA  = TIPO_COMPROBANTE.COMPANIA
    AND DETALLE_COMPROBANTE_CNT.TIPO_CPTE = TIPO_COMPROBANTE.CODIGO
WHERE DETALLE_COMPROBANTE_CNT.COMPANIA=s$compania$s
  AND (VLRAGIRAR-CASE WHEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO>0 AND DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO=DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO THEN DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO ELSE DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO-DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO END + ABONADO) >0
  AND DETALLE_COMPROBANTE_CNT.FECHA<=TO_DATE('s$fechaCorte$s','DD/MM/YYYY')
  AND V_PLAN_CONTABLE.CLASECUENTA IN ('P','E')
  AND TIPO_COMPROBANTE.CLASE_CONTABLE IN ('P')
  AND TERCERO.NIT BETWEEN 's$terceroInicial$s' AND 's$terceroFinal$s' 
   s$soloAprobados$s]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);